{"command": "cd /testbed && python -c "
import django
from django.conf import settings
settings.configure()
django.setup()

from django.core.validators import URLValidator
v = URLValidator()

print('Testing all valid URLs from file...')
with open('tests/validators/valid_urls.txt', encoding='utf8') as f:
    for line in f:
        url = line.strip()
        if url:
            try:
                v(url)
            except Exception as e:
                print(f'FAIL (should be valid): {url} - {e}')

print('Testing all invalid URLs from file...')
with open('tests/validators/invalid_urls.txt', encoding='utf8') as f:
    for line in f:
        url = line.strip()
        if url:
            try:
                v(url)
                print(f'FAIL (should be invalid): {url}')
            except Exception:
                pass  # Expected

print('Done!')
"
"}

